"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { Icon } from "@/components/shared/icon";
import { getPageMeta, navigationItems } from "@/lib/navigation";
import { cx } from "@/lib/utils";

export function TopHeader() {
  const pathname = usePathname();
  const meta = getPageMeta(pathname);

  return (
    <header className="sticky top-0 z-20 border-b border-white/6 bg-[rgba(6,17,26,0.78)] px-4 py-4 backdrop-blur-xl sm:px-6 lg:px-8">
      <div className="flex flex-col gap-4">
        <div className="flex flex-col gap-4 xl:flex-row xl:items-center xl:justify-between">
          <div>
            <p className="text-[11px] font-semibold uppercase tracking-[0.28em] text-cyan-300/75">
              {meta.eyebrow}
            </p>
            <h2 className="mt-2 text-2xl font-semibold tracking-tight text-white">
              {meta.title}
            </h2>
            <p className="mt-2 max-w-3xl text-sm leading-6 text-[var(--foreground-muted)]">
              {meta.description}
            </p>
          </div>

          <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
            <label className="panel-soft flex min-w-[280px] items-center gap-3 rounded-2xl px-4 py-3 text-sm text-[var(--foreground-muted)]">
              <Icon name="search" className="h-4 w-4 text-slate-400" />
              <input
                type="search"
                placeholder="搜索任务、模板或执行日志"
                className="w-full bg-transparent text-sm text-white outline-none placeholder:text-slate-500"
              />
            </label>

            <button
              type="button"
              className="rounded-2xl border border-white/10 bg-white/6 px-4 py-3 text-sm font-semibold text-slate-100 transition hover:border-cyan-400/20 hover:bg-cyan-400/10"
            >
              连接底座
            </button>

            <Link
              href="/tasks"
              className="rounded-2xl border border-cyan-400/20 bg-cyan-400/14 px-4 py-3 text-sm font-semibold text-cyan-100 transition hover:bg-cyan-400/18"
            >
              新建任务
            </Link>
          </div>
        </div>

        <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-thin lg:hidden">
          {navigationItems.map((item) => {
            const active =
              item.href === "/"
                ? pathname === "/"
                : item.matchPrefixes.some((prefix) => pathname.startsWith(prefix));

            return (
              <Link
                key={item.href}
                href={item.href}
                className={cx(
                  "flex shrink-0 items-center gap-2 rounded-full border px-3 py-2 text-xs font-semibold",
                  active
                    ? "border-cyan-400/20 bg-cyan-400/10 text-cyan-100"
                    : "border-white/8 bg-white/4 text-slate-300",
                )}
              >
                <Icon name={item.icon} className="h-4 w-4" />
                {item.shortLabel}
              </Link>
            );
          })}
        </div>
      </div>
    </header>
  );
}
